  beneficial_owners_id                TEXT                 PRIMARY KEY          -- Primary key (auto-synthesized: BeneficialOwners had no field named 'Id' or ending in 'Id').
);
ALTER TABLE beneficial_owners ADD COLUMN IF NOT EXISTS business TEXT;                               -- FK to the parent Business.
