ALTER TABLE beneficial_owners ADD COLUMN IF NOT EXISTS address_encrypted TEXT;                      -- Encrypted home address (PII, FieldLevelEncryption).
ALTER TABLE beneficial_owners ADD COLUMN IF NOT EXISTS ownership_percentage NUMERIC;                -- Percent of the Business owned by this individual (0-100).
ALTER TABLE beneficial_owners ADD COLUMN IF NOT EXISTS is_control_person BOOLEAN;                   -- True when this individual is the designated control person per CDD (one is required when no owner crosses 25%).
