  risk_rating_history_id              TEXT                 PRIMARY KEY          -- Primary key (auto-synthesized: RiskRatingHistory had no field named 'Id' or ending in 'Id').
);
ALTER TABLE risk_rating_history ADD COLUMN IF NOT EXISTS loan TEXT;                                 -- FK to the Loan whose grade changed.
ALTER TABLE risk_rating_history ADD COLUMN IF NOT EXISTS changed_by_user TEXT;                      -- FK to Users: who recorded the migration.
ALTER TABLE risk_rating_history ADD COLUMN IF NOT EXISTS effective_date TIMESTAMPTZ;                -- Date the new grade takes effect.
ALTER TABLE risk_rating_history ADD COLUMN IF NOT EXISTS prior_grade INTEGER;                       -- Grade before this change; null on initial rating.
ALTER TABLE risk_rating_history ADD COLUMN IF NOT EXISTS new_grade INTEGER;                         -- Grade after this change.
ALTER TABLE risk_rating_history ADD COLUMN IF NOT EXISTS reason TEXT;                               -- Free-text justification for the migration.
