-- ----------------------------------------------------------------------------
-- Interactions: Unified activity-log feed for a Business. An Interaction is intentionally generic: InteractionType discriminates Note, Call, Visit, Task, Meeting, or SystemEvent. Covenant breaches, document requests, and other machine actions are written as SystemEvent interactions so they appear in the same stream as human-logged activity.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS interactions (
  interactions_id                     TEXT                 PRIMARY KEY          -- Primary key (auto-synthesized: Interactions had no field named 'Id' or ending in 'Id').
);
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS business TEXT;                                    -- FK to the parent Business.
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS "user" TEXT;                                      -- FK to Users: who logged the interaction (null for system-generated or customer-portal-originated rows).
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS interaction_type TEXT;                            -- Note, Call, Visit, Task, Meeting, or SystemEvent.
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS subject TEXT;                                     -- Short subject line (used in compound PK).
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS body TEXT;                                        -- Long-form body of the interaction.
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS interaction_date TIMESTAMPTZ;                     -- Date the interaction occurred or was logged.
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS due_date TIMESTAMPTZ;                             -- For Task-type interactions: due date.
ALTER TABLE interactions ADD COLUMN IF NOT EXISTS source TEXT;                                      -- Origin surface: RMDashboard, BusinessClientPortal, BranchBankerPortal, SystemEvent.
COMMENT ON TABLE interactions IS 'Unified activity-log feed for a Business. An Interaction is intentionally generic: InteractionType discriminates Note, Call, Visit, Task, Meeting, or SystemEvent. Covenant breaches, document requests, and other machine actions are written as SystemEvent interactions so they appear in the same stream as human-logged activity.';
COMMENT ON COLUMN interactions.interactions_id IS 'Primary key (auto-synthesized: Interactions had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN interactions.business IS 'FK to the parent Business.';
